import { apiClient } from './api';

export const getCourses = (page = 1, limit = 10, filters = {}) => {
  const queryParams = new URLSearchParams({
    page: page.toString(),
    limit: limit.toString(),
    ...Object.fromEntries(Object.entries(filters).filter(([_, v]) => v != null && v !== '')),
  } as Record<string, string>).toString();
  return apiClient(`/courses?${queryParams}`);
};

export const createCourse = (data: any) =>
  apiClient('/courses', {
    method: 'POST',
    body: JSON.stringify(data),
  });

export const updateCourse = (id: string, data: any) =>
  apiClient(`/courses/${id}`, {
    method: 'PUT',
    body: JSON.stringify(data),
  });

export const deleteCourse = (id: string) =>
  apiClient(`/courses/${id}`, {
    method: 'DELETE',
  });

export const exportCourses = async (filters = {}) => {
  const queryParams = new URLSearchParams(
    Object.fromEntries(Object.entries(filters).filter(([_, v]) => v != null && v !== '')) as Record<string, string>,
  );

  const blob = await apiClient<Blob>(`/courses/export?${queryParams.toString()}`, {
    responseType: 'blob',
  });

  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `danh_sach_khoa_hoc_${new Date().getTime()}.xlsx`;
  document.body.appendChild(a);
  a.click();
  window.URL.revokeObjectURL(url);
  document.body.removeChild(a);
};

export const getUnassignedStudents = (params = {}) => {
  const queryParams = new URLSearchParams(
    Object.fromEntries(Object.entries(params).filter(([_, v]) => v != null && v !== '')) as Record<string, string>,
  ).toString();
  return apiClient(`/courses/unassigned?${queryParams}`);
};

