import { apiClient } from './api';

// Types
export interface CancelPreview {
  hasPayments: boolean;
  paymentCount?: number;
  hasDatSessions: boolean;
  datCompleted: boolean;
  totalDatKm?: number;
  warnings: string[];
}

export interface EnrollmentHistory {
  active: any | null;
  history: any[];
}

/**
 * Get enrollment history for a student (active + canceled)
 * GET /api/v1/course-students/student/:studentId
 */
export const getEnrollmentHistory = (studentId: string): Promise<{ success: boolean; data: EnrollmentHistory }> => {
  return apiClient(`/course-students/student/${studentId}`);
};

/**
 * Get cancel preview (warnings before confirming cancellation)
 * GET /api/v1/course-students/:id/cancel-preview
 */
export const getCancelPreview = (enrollmentId: string): Promise<{ success: boolean; data: CancelPreview }> => {
  return apiClient(`/course-students/${enrollmentId}/cancel-preview`);
};

/**
 * Cancel an enrollment (soft delete)
 * PATCH /api/v1/course-students/:id/cancel
 */
export const cancelEnrollment = (
  enrollmentId: string,
  reason: string,
): Promise<{ success: boolean; message: string; data: any }> => {
  return apiClient(`/course-students/${enrollmentId}/cancel`, {
    method: 'PATCH',
    body: JSON.stringify({ reason }),
  });
};

'use client';

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { AlertTriangle, X, AlertCircle, CheckCircle2, Loader2, ChevronRight, CreditCard, Route } from 'lucide-react';
import { toast } from 'sonner';
import { getCancelPreview, cancelEnrollment, CancelPreview } from '@/src/services/courseStudentService';

type CancelDialogStep = 'preview' | 'confirm';

interface EnrollmentCancelDialogProps {
  isOpen: boolean;
  onClose: () => void;
  enrollmentId: string;
  enrollmentName: string;
  studentName: string;
  onSuccess: () => void;
}

export default function EnrollmentCancelDialog({
  isOpen,
  onClose,
  enrollmentId,
  enrollmentName,
  studentName,
  onSuccess,
}: EnrollmentCancelDialogProps) {
  const [step, setStep] = useState<CancelDialogStep>('preview');
  const [preview, setPreview] = useState<CancelPreview | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [reason, setReason] = useState('');
  const [reasonError, setReasonError] = useState('');
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      setStep('preview');
      setReason('');
      setReasonError('');
      setPreview(null);
      fetchPreview();
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, [isOpen, enrollmentId]);

  const fetchPreview = async () => {
    setIsLoading(true);
    try {
      const res = await getCancelPreview(enrollmentId);
      if (res.success) {
        setPreview(res.data);
      } else {
        toast.error('Không thể tải thông tin hủy khóa. Vui lòng thử lại.');
        onClose();
      }
    } catch (e) {
      console.error('Error fetching cancel preview:', e);
      toast.error('Lỗi kết nối khi tải thông tin hủy khóa.');
      onClose();
    } finally {
      setIsLoading(false);
    }
  };

  const handleConfirmStep = () => {
    if (!reason.trim()) {
      setReasonError('Vui lòng nhập lý do hủy khóa học.');
      return;
    }
    if (reason.trim().length < 5) {
      setReasonError('Lý do phải có ít nhất 5 ký tự.');
      return;
    }
    setReasonError('');
    performCancel();
  };

  const performCancel = async () => {
    setIsSubmitting(true);
    try {
      const res = await cancelEnrollment(enrollmentId, reason.trim());
      if (res.success) {
        toast.success('Đã hủy khóa học thành công!');
        onSuccess();
        onClose();
      } else {
        toast.error(res.message || 'Không thể hủy khóa học. Vui lòng thử lại.');
      }
    } catch (e: any) {
      console.error('Error canceling enrollment:', e);
      toast.error(e?.message || 'Lỗi kết nối khi hủy khóa học.');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!isOpen || !mounted) return null;

  const dialogContent = (
    <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 sm:p-6 overflow-y-auto">
      {/* Backdrop */}
      <div
        className="fixed inset-0 bg-gray-900/50 backdrop-blur-sm animate-in fade-in duration-300"
        onClick={onClose}
      />

      {/* Dialog */}
      <div className="relative w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl shadow-gray-900/10 border border-gray-100 overflow-hidden animate-in zoom-in-95 fade-in duration-300 z-[10000]">
        {/* Header accent bar */}
        <div className="h-2 bg-rose-500" />

        {/* Close button */}
        <button
          onClick={onClose}
          className="absolute top-5 right-5 p-2 text-gray-400 hover:text-gray-900 hover:bg-gray-100 rounded-xl transition-all z-10"
        >
          <X className="w-5 h-5" />
        </button>

        {/* STEP 1: PREVIEW */}
        {step === 'preview' && (
          <div className="p-8">
            {/* Icon */}
            <div className="flex flex-col items-center text-center gap-4 mb-6">
              {isLoading ? (
                <>
                  <div className="w-16 h-16 bg-gray-100 rounded-2xl flex items-center justify-center animate-pulse">
                    <Loader2 className="w-8 h-8 text-gray-400 animate-spin" />
                  </div>
                  <div>
                    <p className="text-base font-bold text-gray-700">Đang kiểm tra thông tin...</p>
                    <p className="text-sm text-gray-400 mt-1">Vui lòy chờ trong giây lát</p>
                  </div>
                </>
              ) : (
                <>
                  <div className="w-16 h-16 bg-rose-100 rounded-2xl flex items-center justify-center">
                    <AlertTriangle className="w-8 h-8 text-rose-600" />
                  </div>
                  <div>
                    <h3 className="text-xl font-black text-gray-900">Hủy khóa học</h3>
                    <p className="text-sm text-gray-500 mt-1 font-medium">
                      Khóa: <span className="text-indigo-600 font-bold">{enrollmentName}</span>
                    </p>
                    <p className="text-xs text-gray-400">
                      Học viên: <span className="font-semibold text-gray-600">{studentName}</span>
                    </p>
                  </div>
                </>
              )}
            </div>

            {/* Loading state */}
            {isLoading && (
              <div className="space-y-3">
                {[1, 2].map((i) => (
                  <div key={i} className="h-16 bg-gray-100 rounded-xl animate-pulse" />
                ))}
              </div>
            )}

            {/* Warnings */}
            {!isLoading && preview && (
              <div className="space-y-3 mb-8">
                {/* Special warnings from spec */}
                {preview.hasPayments && (
                  <div className="flex items-start gap-3 p-4 bg-amber-50 border border-amber-100 rounded-2xl">
                    <div className="w-8 h-8 bg-amber-100 rounded-xl flex items-center justify-center shrink-0 mt-0.5">
                      <CreditCard className="w-4 h-4 text-amber-600" />
                    </div>
                    <div className="flex-1">
                      <p className="text-sm font-bold text-amber-800">
                        Đã có {preview.paymentCount ?? 'nhiều'} khoản thanh toán
                      </p>
                      <p className="text-xs text-amber-600 mt-0.5 font-medium">
                        Sẽ được giữ lại trong lịch sử thanh toán.
                      </p>
                    </div>
                  </div>
                )}

                {preview.datCompleted && (
                  <div className="flex items-start gap-3 p-4 bg-blue-50 border border-blue-100 rounded-2xl">
                    <div className="w-8 h-8 bg-blue-100 rounded-xl flex items-center justify-center shrink-0 mt-0.5">
                      <Route className="w-4 h-4 text-blue-600" />
                    </div>
                    <div className="flex-1">
                      <p className="text-sm font-bold text-blue-800">
                        Đã hoàn thành DAT ({preview.totalDatKm ?? 0}km)
                      </p>
                      <p className="text-xs text-blue-600 mt-0.5 font-medium">
                        Tiến độ sẽ được giữ trong lịch sử học viên.
                      </p>
                    </div>
                  </div>
                )}

                {/* General warnings from API */}
                {preview.warnings && preview.warnings.length > 0 && (
                  <div className="flex flex-col gap-2">
                    {preview.warnings.map((warning, idx) => (
                      <div
                        key={idx}
                        className="flex items-start gap-2 p-3 bg-gray-50 border border-gray-100 rounded-xl"
                      >
                        <AlertCircle className="w-4 h-4 text-gray-400 shrink-0 mt-0.5" />
                        <p className="text-xs text-gray-600 font-medium">{warning}</p>
                      </div>
                    ))}
                  </div>
                )}

                {/* No warnings - positive signal */}
                {!preview.hasPayments && !preview.datCompleted && (!preview.warnings || preview.warnings.length === 0) && (
                  <div className="flex items-start gap-3 p-4 bg-emerald-50 border border-emerald-100 rounded-2xl">
                    <div className="w-8 h-8 bg-emerald-100 rounded-xl flex items-center justify-center shrink-0 mt-0.5">
                      <CheckCircle2 className="w-4 h-4 text-emerald-600" />
                    </div>
                    <div className="flex-1">
                      <p className="text-sm font-bold text-emerald-800">Không có cảnh báo</p>
                      <p className="text-xs text-emerald-600 mt-0.5 font-medium">
                        Khóa học này có thể hủy mà không ảnh hưởng đến dữ liệu khác.
                      </p>
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Actions */}
            {!isLoading && (
              <div className="flex items-center gap-3">
                <button
                  onClick={onClose}
                  className="flex-1 px-6 py-4 bg-gray-50 text-gray-700 font-black rounded-2xl border border-gray-200 hover:bg-gray-100 transition-all text-xs uppercase tracking-widest"
                >
                  Không, giữ lại
                </button>
                <button
                  onClick={() => setStep('confirm')}
                  className="flex-1 flex items-center justify-center gap-2 px-6 py-4 bg-rose-600 hover:bg-rose-700 text-white font-black rounded-2xl shadow-xl shadow-rose-500/20 transition-all text-xs uppercase tracking-widest hover:scale-105 active:scale-95"
                >
                  Tiếp tục hủy <ChevronRight className="w-4 h-4" />
                </button>
              </div>
            )}
          </div>
        )}

        {/* STEP 2: CONFIRM WITH REASON */}
        {step === 'confirm' && (
          <div className="p-8">
            <div className="flex flex-col items-center text-center gap-4 mb-6">
              <div className="w-16 h-16 bg-rose-100 rounded-2xl flex items-center justify-center">
                <AlertTriangle className="w-8 h-8 text-rose-600" />
              </div>
              <div>
                <h3 className="text-xl font-black text-gray-900">Xác nhận hủy khóa học?</h3>
                <p className="text-sm text-gray-500 mt-1 font-medium">
                  Khóa: <span className="text-indigo-600 font-bold">{enrollmentName}</span>
                </p>
              </div>
            </div>

            {/* Reason input */}
            <div className="mb-8">
              <label className="block text-xs font-extrabold uppercase tracking-tight text-gray-500 mb-2">
                Lý do hủy khóa <span className="text-rose-500">*</span>
              </label>
              <textarea
                value={reason}
                onChange={(e) => {
                  setReason(e.target.value);
                  if (reasonError) setReasonError('');
                }}
                placeholder="VD: Học viên xin chuyển sang khóa B2-2026-A2, học viên tự nguyện rời khóa..."
                rows={4}
                className={`w-full px-4 py-3 bg-white border rounded-2xl text-sm font-medium resize-none transition-all focus:outline-none focus:ring-4 ${
                  reasonError
                    ? 'border-rose-300 focus:ring-rose-500/10 focus:border-rose-500 bg-rose-50/20'
                    : 'border-gray-200 focus:ring-indigo-500/10 focus:border-indigo-500'
                }`}
              />
              {reasonError && (
                <p className="text-xs text-rose-500 font-bold mt-1.5 ml-1">{reasonError}</p>
              )}
              <p className="text-[10px] text-gray-400 mt-1.5 text-right">
                {reason.length} ký tự
              </p>
            </div>

            {/* Info note */}
            <div className="mb-6 p-3 bg-gray-50 border border-gray-100 rounded-xl">
              <p className="text-xs text-gray-500 font-medium leading-relaxed">
                ⚠️ Sau khi hủy, học viên sẽ quay về trạng thái <strong>"Chưa vào khóa"</strong> và có thể được đăng ký vào khóa học mới. Các dữ liệu đã ghi nhận (thanh toán, buổi DAT...) sẽ được giữ lại trong lịch sử.
              </p>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-3">
              <button
                onClick={() => setStep('preview')}
                className="flex-1 px-6 py-4 bg-gray-50 text-gray-700 font-black rounded-2xl border border-gray-200 hover:bg-gray-100 transition-all text-xs uppercase tracking-widest"
                disabled={isSubmitting}
              >
                ← Quay lại
              </button>
              <button
                onClick={handleConfirmStep}
                disabled={isSubmitting}
                className="flex-1 flex items-center justify-center gap-2 px-6 py-4 bg-rose-600 hover:bg-rose-700 text-white font-black rounded-2xl shadow-xl shadow-rose-500/20 transition-all text-xs uppercase tracking-widest hover:scale-105 active:scale-95 disabled:opacity-50 disabled:hover:scale-100"
              >
                {isSubmitting ? (
                  <Loader2 className="w-4 h-4 animate-spin" />
                ) : (
                  <AlertTriangle className="w-4 h-4" />
                )}
                Hủy khóa
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );

  return createPortal(dialogContent, document.body);
}

